def solve(*args):
    if not args:
        return None

    # Assuming args should contain a list of resources
    resources = list(args)

    # Validate inputs vs contract
    for resource in resources:
        if not isinstance(resource, str):
            raise ValueError("All resources must be strings.")

    # Implement core logic to track resources
    tracked_resources = {}

    for resource in resources:
        if resource not in tracked_resources:
            tracked_resources[resource] = 1
        else:
            tracked_resources[resource] += 1

    return tracked_resources
